function getTheme(theme, mod) {
  const base = theme === "light" ? LIGHT : DARK;
  const mc = MODULE_COLORS[mod]?.[theme === "light" ? "l" : "d"] || MODULE_COLORS.jobs[theme === "light" ? "l" : "d"];
  return { ...base, accent: mc.accent, accentGrad: mc.grad, accentSoft: mc.soft, accentBorder: mc.border, hoverBorder: mc.hover, tagColor: mc.tag, tagBg: mc.tagBg, accentText: mc.accentText };
}
