function loadS(k){try{const r=localStorage.getItem(k);return r?JSON.parse(r):null}catch{return null}}
function saveS(k,d){try{localStorage.setItem(k,JSON.stringify(d))}catch(e){console.error(e)}}
function loadAll(){let j=loadS(SK.jobs)||[];if(!j.length){const o=loadS("ayis-apps")||[];if(o.length){j=o;saveS(SK.jobs,j)}}return{jobs:j,exams:loadS(SK.exams)||[],masters:loadS(SK.masters)||[],settings:loadS(SK.settings)||{name:"",theme:"dark"}}}
