function Moon({spin}){return <span style={{display:"inline-block",transition:"transform 0.6s cubic-bezier(0.34,1.56,0.64,1)",transform:spin?"rotate(360deg)":"rotate(0deg)",fontSize:36}}>☾</span>}
function TagInput({tags,onChange,S}){const[input,setInput]=useState("");const add=()=>{const t=input.trim();if(t&&!tags.includes(t))onChange([...tags,t]);setInput("")};return <div style={{marginBottom:12}}><label style={S.label}>Etiketler</label><div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:6}}>{tags.map(t=><span key={t} style={S.tag}>{t}<button style={S.tagRemove} onClick={()=>onChange(tags.filter(x=>x!==t))}>×</button></span>)}</div><input style={{...S.input,fontSize:13}} placeholder="Etiket yaz, Enter'a bas" value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"){e.preventDefault();add()}}}/></div>}
function EmptyState({icon,text,onAdd,S}){return <div style={S.empty}><div style={{fontSize:48,marginBottom:12}}>{icon||"☾"}</div><div style={{fontSize:16}}>{text}</div>{onAdd&&<div style={{marginTop:6}}><button style={{...S.primaryBtn,fontSize:13,padding:"8px 20px"}} onClick={onAdd}>+ Yeni Ekle</button></div>}</div>}
function ModuleSwitcher({current,onChange,S}){const[open,setOpen]=useState(false);const mod=MODULES.find(m=>m.key===current);return <div style={{position:"relative"}}><button style={S.moduleBtn} onClick={()=>setOpen(!open)}>{mod.label} <span style={{fontSize:10,opacity:0.6}}>▼</span></button>{open&&<div style={S.moduleMenu}>{MODULES.map(m=><button key={m.key} style={S.moduleMenuItem(m.key===current)} onClick={()=>{onChange(m.key);setOpen(false)}}>{m.label}</button>)}</div>}</div>}
function SettingsModal({settings,onSave,onClose,S}){const[f,sF]=useState({...settings});return <div style={S.modal} onClick={onClose}><div style={{...S.modalInner,maxWidth:400}} onClick={e=>e.stopPropagation()}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h2 style={{margin:0,fontSize:20,color:S.T.accent}}>Ayarlar</h2><button onClick={onClose} style={{background:"none",border:"none",color:S.T.textSub,fontSize:22,cursor:"pointer"}}>✕</button></div><div style={{marginBottom:16}}><label style={S.label}>Adınız</label><input style={S.input} value={f.name} onChange={e=>sF({...f,name:e.target.value})} placeholder="Adınızı girin..."/></div><div style={{marginBottom:20}}><label style={S.label}>Tema</label><div style={{display:"flex",gap:8}}>{[{key:"dark",label:"☾ Koyu"},{key:"light",label:"☀ Açık"}].map(t=><button key={t.key} onClick={()=>sF({...f,theme:t.key})} style={{...S.filterChip(f.theme===t.key),padding:"10px 20px",fontSize:14,flex:1}}>{t.label}</button>)}</div></div><button style={{...S.primaryBtn,width:"100%"}} onClick={()=>onSave(f)}>Kaydet</button></div></div>}
const urgencyColor=d=>d<=1?"#E74C5A":d<=3?"#E8A838":"#4EC9A0";
const urgencyBg=d=>d<=1?"rgba(231,76,90,0.12)":d<=3?"rgba(232,168,56,0.12)":"rgba(78,201,160,0.12)";
const urgencyLabel=d=>d===0?"Bugün":d===1?"Yarın":d+" gün";
function statusCardStyle(status,S){const red=["rejected","withdrawn","failed"].includes(status);const green=["accepted","passed"].includes(status);if(red)return{...S.card,borderLeft:"3px solid #E74C5A"};if(green)return{...S.card,borderLeft:"3px solid #2ECC71"};return S.card}
function UpcomingEvents({jobs,exams,masters,S}){const items=[];(jobs||[]).forEach(a=>{(a.interviewStages||[]).forEach(st=>{if(st.date&&st.result==="pending"){const d=daysUntil(st.date);if(d!==null&&d>=0&&d<=14)items.push({type:"Mülakat",tc:"#E8A838",title:a.company+" — "+a.position,sub:(st.type||"Mülakat")+" · "+formatDate(st.date),days:d})}})});(jobs||[]).filter(a=>a.status==="planned"&&a.deadline).forEach(a=>{const d=daysUntil(a.deadline);if(d!==null&&d>=0&&d<=14)items.push({type:"Son Başvuru",tc:"#7C6F9B",title:a.company+" — "+a.position,sub:formatDate(a.deadline),days:d})});(exams||[]).forEach(e=>{if(e.examDate&&["planned","registered"].includes(e.status)){const d=daysUntil(e.examDate);if(d!==null&&d>=0&&d<=30)items.push({type:"Sınav",tc:"#5B9BD5",title:e.name,sub:formatDate(e.examDate)+(e.location?" · "+e.location:""),days:d})}if(e.registrationDeadline&&e.status==="planned"){const d=daysUntil(e.registrationDeadline);if(d!==null&&d>=0&&d<=14)items.push({type:"Kayıt Son Tarih",tc:"#E8A838",title:e.name,sub:formatDate(e.registrationDeadline),days:d})}});(masters||[]).filter(m=>m.deadline&&["researching","preparing"].includes(m.status)).forEach(m=>{const d=daysUntil(m.deadline);if(d!==null&&d>=0&&d<=30)items.push({type:"YL Başvuru",tc:"#D4A843",title:m.university+" — "+m.program,sub:formatDate(m.deadline)+(m.semester?" · "+m.semester:""),days:d})});items.sort((a,b)=>a.days-b.days);if(!items.length)return null;return <div style={{marginBottom:24}}><div style={{...S.sectionTitle,color:"#E8A838"}}>Yaklaşan Etkinlikler</div>{items.map((it,i)=><div key={i} style={{...S.card,cursor:"default",borderLeft:"3px solid "+urgencyColor(it.days),display:"flex",justifyContent:"space-between",alignItems:"center"}}><div><div style={{fontSize:11,color:it.tc,fontWeight:700,textTransform:"uppercase",marginBottom:3}}>{it.type}</div><div style={{fontWeight:700,fontSize:14}}>{it.title}</div><div style={{fontSize:12,color:S.T.textSub,marginTop:2}}>{it.sub}</div></div><span style={{padding:"4px 10px",borderRadius:8,fontSize:12,fontWeight:700,color:urgencyColor(it.days),background:urgencyBg(it.days)}}>{urgencyLabel(it.days)}</span></div>)}</div>}
