function DocChecklist({documents,onChange,S}){const[nd,sNd]=useState("");const[adding,sAdding]=useState(false);const toggle=i=>onChange(documents.map((d,j)=>j===i?{...d,done:!d.done}:d));const add=()=>{if(nd.trim()){onChange([...documents,{name:nd.trim(),done:false}]);sNd("");sAdding(false)}};const rm=i=>onChange(documents.filter((_,j)=>j!==i));const dc=documents.filter(d=>d.done).length,pct=documents.length?Math.round((dc/documents.length)*100):0;return <div style={{marginBottom:12}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}><div style={S.sectionTitle}>Gerekli Belgeler</div><div style={{display:"flex",alignItems:"center",gap:8}}><span style={{fontSize:11,color:S.T.textSub}}>{dc}/{documents.length}</span><button onClick={()=>sAdding(!adding)} style={{padding:"4px 10px",border:"1px solid "+S.T.accentBorder,borderRadius:6,background:S.T.accentSoft,color:S.T.accent,fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:font}}>+ Belge</button></div></div>{adding&&<div style={{display:"flex",gap:6,marginBottom:10}}><input style={{...S.input,fontSize:13,flex:1}} placeholder="Belge adı yazın..." value={nd} onChange={e=>sNd(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"){e.preventDefault();add()}}} autoFocus/><button onClick={add} style={{padding:"8px 14px",border:"none",borderRadius:8,cursor:"pointer",background:S.T.accentSoft,color:S.T.accent,fontSize:12,fontWeight:600,fontFamily:font,whiteSpace:"nowrap"}}>Ekle</button></div>}<div style={{background:S.T.barBg,borderRadius:8,overflow:"hidden",height:6,marginBottom:10}}><div style={{height:"100%",width:pct+"%",background:pct===100?"#2ECC71":S.T.accent,transition:"width 0.3s",borderRadius:8}}/></div>{documents.map((d,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:8,padding:"6px 0",borderBottom:"1px solid "+S.T.cardBorder}}><button onClick={()=>toggle(i)} style={{width:20,height:20,borderRadius:5,border:d.done?"none":"1.5px solid "+S.T.inputBorder,background:d.done?"#2ECC71":"transparent",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontSize:12,fontWeight:700,flexShrink:0}}>{d.done?"✓":""}</button><span style={{flex:1,fontSize:13,color:d.done?"#4EC9A0":S.T.textSub,textDecoration:d.done?"line-through":"none"}}>{d.name}</span><button onClick={()=>rm(i)} style={{background:"none",border:"none",color:S.T.textMuted,cursor:"pointer",fontSize:14,padding:"0 2px"}}>×</button></div>)}</div>}
function MastersModal({item,onSave,onClose,onDelete,S}){const[f,sF]=useState(()=>item?{...item,tags:item.tags||[],documents:item.documents||DEFAULT_DOCS.map(d=>({name:d,done:false}))}:emptyMasters());const isE=!!item;const s=(k,v)=>sF(p=>({...p,[k]:v}));return <div style={S.modal} onClick={onClose}><div style={S.modalInner} onClick={e=>e.stopPropagation()}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h2 style={{margin:0,fontSize:20,color:S.T.accent}}>{isE?"Başvuruyu Düzenle":"Yeni YL Başvurusu"}</h2><button onClick={onClose} style={{background:"none",border:"none",color:S.T.textSub,fontSize:22,cursor:"pointer"}}>✕</button></div><div style={S.row}><div style={S.col2}><label style={S.label}>Üniversite *</label><input style={S.input} value={f.university} onChange={e=>s("university",e.target.value)} placeholder="Örn: ODTÜ"/></div><div style={S.col2}><label style={S.label}>Program / Bölüm *</label><input style={S.input} value={f.program} onChange={e=>s("program",e.target.value)} placeholder="Örn: Endüstri Mühendisliği"/></div></div><div style={S.row}><div style={S.col3}><label style={S.label}>Ülke / Şehir</label><input style={S.input} value={f.country} onChange={e=>s("country",e.target.value)}/></div><div style={S.col3}><label style={S.label}>Dönem</label><input style={S.input} value={f.semester} onChange={e=>s("semester",e.target.value)} placeholder="Örn: Güz 2026"/></div><div style={S.col3}><label style={S.label}>Durum</label><select style={S.select} value={f.status} onChange={e=>s("status",e.target.value)}>{MASTERS_STATUS.map(st=><option key={st.key} value={st.key}>{st.label}</option>)}</select></div></div><div style={S.row}><div style={S.col2}><label style={S.label}>Son Başvuru Tarihi</label><input type="date" style={S.input} value={f.deadline} onChange={e=>s("deadline",e.target.value)}/></div><div style={S.col2}><label style={S.label}>Burs / Ücret</label><input style={S.input} value={f.scholarship} onChange={e=>s("scholarship",e.target.value)} placeholder="Örn: Tam burslu"/></div></div><div style={S.col1}><label style={S.label}>Program Linki</label><input style={S.input} value={f.link} onChange={e=>s("link",e.target.value)} placeholder="https://..."/></div><div style={S.row}><div style={S.col2}><label style={S.label}>İletişim Kişisi</label><input style={S.input} value={f.contactName} onChange={e=>s("contactName",e.target.value)}/></div><div style={S.col2}><label style={S.label}>İletişim Bilgisi</label><input style={S.input} value={f.contactInfo} onChange={e=>s("contactInfo",e.target.value)}/></div></div><DocChecklist documents={f.documents} onChange={d=>s("documents",d)} S={S}/><TagInput tags={f.tags} onChange={t=>s("tags",t)} S={S}/><div style={S.col1}><label style={S.label}>Notlar</label><textarea style={S.textarea} value={f.notes} onChange={e=>s("notes",e.target.value)}/></div><div style={{display:"flex",gap:10,justifyContent:"space-between",marginTop:16,flexWrap:"wrap"}}><div>{isE&&<button style={S.dangerBtn} onClick={()=>onDelete(f.id)}>Sil</button>}</div><div style={{display:"flex",gap:10}}><button style={S.secondaryBtn} onClick={onClose}>İptal</button><button style={{...S.primaryBtn,opacity:(!f.university.trim()||!f.program.trim())?0.4:1}} onClick={()=>{if(f.university.trim()&&f.program.trim())onSave(f)}}>{isE?"Güncelle":"Kaydet"}</button></div></div></div></div>}
function MastersCard({item,onClick,S}){const st=MASTERS_STATUS.find(s=>s.key===item.status);const dl=daysUntil(item.deadline);const docs=item.documents||[];const dc=docs.filter(d=>d.done).length,pct=docs.length?Math.round((dc/docs.length)*100):0;const cStyle=statusCardStyle(item.status,S);return <div style={cStyle} onClick={onClick} onMouseEnter={e=>{e.currentTarget.style.borderColor=S.T.hoverBorder;e.currentTarget.style.transform="translateY(-1px)"}} onMouseLeave={e=>{e.currentTarget.style.borderColor=S.T.cardBorder;e.currentTarget.style.transform="translateY(0)"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:12,flexWrap:"wrap"}}><div style={{flex:1,minWidth:180}}><div style={{fontWeight:700,fontSize:16,marginBottom:4}}>{item.university}</div><div style={{fontSize:14,color:S.T.textSub,marginBottom:6}}>{item.program}</div><div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>{item.country&&<span style={{fontSize:12,color:S.T.textMuted}}>{item.country}</span>}{item.semester&&<span style={{fontSize:12,color:S.T.textMuted}}>· {item.semester}</span>}{item.scholarship&&<span style={{fontSize:12,color:"#4EC9A0"}}>· {item.scholarship}</span>}</div>{["researching","preparing"].includes(item.status)&&dl!==null&&dl>=0&&dl<=30&&<div style={{fontSize:11,color:urgencyColor(Math.min(dl,7)),marginTop:4}}>Son başvuru: {formatDate(item.deadline)} ({urgencyLabel(dl)} kaldı)</div>}</div><div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:6}}><span style={S.badge(st)}>{st.label}</span>{docs.length>0&&<span style={{fontSize:11,color:pct===100?"#2ECC71":S.T.textSub}}>{dc}/{docs.length} belge</span>}</div></div>{docs.length>0&&<div style={{background:S.T.barBg,borderRadius:4,overflow:"hidden",height:4,marginTop:10}}><div style={{height:"100%",width:pct+"%",background:pct===100?"#2ECC71":S.T.accent,borderRadius:4}}/></div>}{(item.tags||[]).length>0&&<div style={{display:"flex",gap:5,marginTop:8,flexWrap:"wrap"}}>{item.tags.map(t=><span key={t} style={S.tag}>{t}</span>)}</div>}{item.notes&&<div style={{marginTop:10,fontSize:12,color:S.T.textMuted,fontStyle:"italic"}}>{item.notes.length>100?item.notes.slice(0,100)+"...":item.notes}</div>}{item.link&&<div style={{marginTop:6}}><a href={item.link} target="_blank" rel="noopener noreferrer" onClick={e=>e.stopPropagation()} style={{fontSize:12,color:"#5B9BD5",textDecoration:"none"}}>Program Linki</a></div>}</div>}
function MastersDashboard({masters,jobs,exams,S}){const rs=masters.filter(m=>m.status==="researching"),pr=masters.filter(m=>m.status==="preparing"),ap=masters.filter(m=>m.status==="applied"),ac=masters.filter(m=>m.status==="accepted");return <div><div style={{...S.row,marginBottom:20}}>{[{l:"Toplam",v:masters.length,c:S.T.accent},{l:"Araştırılan",v:rs.length,c:"#7C6F9B"},{l:"Hazırlanan",v:pr.length,c:"#5B9BD5"},{l:"Başvurulan",v:ap.length,c:"#E8A838"},{l:"Kabul",v:ac.length,c:"#2ECC71"}].map(s=><div key={s.l} style={S.statCard}><div style={S.statLabel}>{s.l}</div><div style={S.statNum(s.c)}>{s.v}</div></div>)}</div><UpcomingEvents jobs={jobs} exams={exams} masters={masters} S={S}/><div style={S.sectionTitle}>Son Eklenenler</div>{masters.slice().sort((a,b)=>new Date(b.dateCreated)-new Date(a.dateCreated)).slice(0,5).map(m=>{const st=MASTERS_STATUS.find(s=>s.key===m.status);return <div key={m.id} style={{...S.card,display:"flex",justifyContent:"space-between",alignItems:"center",cursor:"default"}}><div><div style={{fontWeight:700,fontSize:15}}>{m.university}</div><div style={{fontSize:13,color:S.T.textSub}}>{m.program}</div></div><span style={S.badge(st)}>{st.label}</span></div>})}{!masters.length&&<EmptyState icon="🎓" text="Henüz yüksek lisans başvurusu yok" S={S}/>}</div>}
export default function AyIs(){
  const[module,setModule]=useState("jobs");
  const[jobs,setJobs]=useState([]);const[exams,setExams]=useState([]);const[masters,setMasters]=useState([]);
  const[settings,setSettings]=useState({name:"",theme:"dark"});
  const[loaded,setLoaded]=useState(false);
  const[tab,setTab]=useState("dashboard");const[modal,setModal]=useState(null);const[settingsOpen,setSettingsOpen]=useState(false);
  const[search,setSearch]=useState("");const[statusFilter,setStatusFilter]=useState("all");const[tagFilter,setTagFilter]=useState("all");
  const[moonSpin,setMoonSpin]=useState(false);
  useEffect(()=>{const d=loadAll();setJobs(d.jobs);setExams(d.exams);setMasters(d.masters);setSettings(d.settings);setLoaded(true)},[]);
  useEffect(()=>{if(loaded)saveS(SK.jobs,jobs)},[jobs,loaded]);
  useEffect(()=>{if(loaded)saveS(SK.exams,exams)},[exams,loaded]);
  useEffect(()=>{if(loaded)saveS(SK.masters,masters)},[masters,loaded]);
  useEffect(()=>{if(loaded)saveS(SK.settings,settings)},[settings,loaded]);
  const spin=()=>{setMoonSpin(true);setTimeout(()=>setMoonSpin(false),700)};
  const reset=()=>{setStatusFilter("all");setTagFilter("all");setSearch("")};
  const switchMod=m=>{setModule(m);setTab("dashboard");reset();setModal(null);spin()};
  const switchTab=t=>{setTab(t);reset();spin()};
  const save=setter=>form=>{setter(prev=>{const i=prev.findIndex(a=>a.id===form.id);if(i>=0){const n=[...prev];n[i]=form;return n}return[...prev,form]});setModal(null)};
  const del=setter=>id=>{setter(prev=>prev.filter(a=>a.id!==id));setModal(null)};
  const T=getTheme(settings.theme,module);
  const SS=useMemo(()=>mkS(T),[settings.theme,module]);
  const mod=MODULES.find(m=>m.key===module);
  const cData=module==="jobs"?jobs:module==="exams"?exams:masters;
  const cStatuses=module==="jobs"?JOB_STATUS:module==="exams"?EXAM_STATUS:MASTERS_STATUS;
  const tabs=module==="jobs"?[{key:"dashboard",label:"Dashboard"},{key:"list",label:"Başvurular"},{key:"watchlist",label:"Watchlist"}]:module==="exams"?[{key:"dashboard",label:"Dashboard"},{key:"list",label:"Sınavlarım"},{key:"watchlist",label:"Planlanan"}]:[{key:"dashboard",label:"Dashboard"},{key:"list",label:"Başvurularım"},{key:"watchlist",label:"Araştırılanlar"}];
  const wStatus=module==="masters"?"researching":"planned";
  const filtered=useMemo(()=>{let list=[...cData];if(tab==="watchlist")list=list.filter(a=>a.status===wStatus);else if(tab==="list")list=list.filter(a=>a.status!==wStatus);if(statusFilter!=="all")list=list.filter(a=>a.status===statusFilter);if(tagFilter!=="all")list=list.filter(a=>(a.tags||[]).includes(tagFilter));if(search.trim()){const q=search.toLowerCase();list=list.filter(a=>{const fs=module==="jobs"?[a.company,a.position,a.location,a.notes]:module==="exams"?[a.name,a.location,a.notes]:[a.university,a.program,a.country,a.notes];return fs.some(f=>(f||"").toLowerCase().includes(q))})}return list.sort((a,b)=>{const dA=module==="jobs"?(a.dateApplied||a.dateCreated):module==="exams"?(a.examDate||a.dateCreated):(a.deadline||a.dateCreated);const dB=module==="jobs"?(b.dateApplied||b.dateCreated):module==="exams"?(b.examDate||b.dateCreated):(b.deadline||b.dateCreated);return new Date(dB)-new Date(dA)})},[cData,module,tab,search,statusFilter,tagFilter]);
  if(!loaded)return <div style={{...SS.app,display:"flex",alignItems:"center",justifyContent:"center",minHeight:"100vh"}}><div style={{textAlign:"center"}}><Moon spin={true}/><div style={{color:T.accent,fontSize:18,marginTop:12,fontFamily:"'Luckiest Guy',cursive"}}>AY.İŞ yükleniyor...</div></div></div>;
  return <div style={SS.app}>
    <div style={SS.content}>
      <div style={SS.header}>
        <h1 style={SS.logo}><Moon spin={moonSpin}/><span style={SS.logoText}>AY.İŞ</span></h1>
        <div style={SS.subtitle}>{mod.subtitle}</div>
        {settings.name&&<div style={SS.greeting}>Merhaba, {settings.name}</div>}
        <div style={SS.topRight}>
          <button style={SS.iconBtn} onClick={()=>setSettingsOpen(true)} title="Ayarlar">⚙</button>
          <ModuleSwitcher current={module} onChange={switchMod} S={SS}/>
        </div>
      </div>
      <div style={SS.nav}>
        {tabs.map(t=><button key={t.key} style={SS.navBtn(tab===t.key)} onClick={()=>switchTab(t.key)}>{t.label}</button>)}
        <button style={{...SS.primaryBtn,padding:"10px 18px",fontSize:13}} onClick={()=>setModal("new")}>+ Yeni Ekle</button>
      </div>
      {tab==="dashboard"&&module==="jobs"&&<JobDashboard jobs={jobs} exams={exams} masters={masters} S={SS}/>}
      {tab==="dashboard"&&module==="exams"&&<ExamDashboard exams={exams} jobs={jobs} masters={masters} S={SS}/>}
      {tab==="dashboard"&&module==="masters"&&<MastersDashboard masters={masters} jobs={jobs} exams={exams} S={SS}/>}
      {(tab==="list"||tab==="watchlist")&&<>
        <div style={SS.searchBar}><input style={{...SS.input,maxWidth:280,flex:"1 1 200px"}} placeholder="Ara..." value={search} onChange={e=>setSearch(e.target.value)}/>{tab==="list"&&<div style={{display:"flex",gap:4,flexWrap:"wrap"}}><button style={SS.filterChip(statusFilter==="all")} onClick={()=>setStatusFilter("all")}>Tümü</button>{cStatuses.filter(s=>s.key!==wStatus).map(s=><button key={s.key} style={SS.filterChip(statusFilter===s.key)} onClick={()=>setStatusFilter(s.key)}>{s.label}</button>)}</div>}</div>
        {(()=>{const at=[...new Set(cData.flatMap(a=>a.tags||[]))].sort();if(!at.length)return null;return <div style={{display:"flex",gap:4,marginBottom:16,flexWrap:"wrap",alignItems:"center"}}><span style={{fontSize:12,color:T.textMuted,marginRight:4}}>Etiket:</span><button style={SS.filterChip(tagFilter==="all")} onClick={()=>setTagFilter("all")}>Tümü</button>{at.map(t=><button key={t} style={SS.filterChip(tagFilter===t)} onClick={()=>setTagFilter(t)}>{t}</button>)}</div>})()}
        <div style={{fontSize:13,color:T.textMuted,marginBottom:12}}>{filtered.length} kayıt gösteriliyor</div>
        {!filtered.length?<EmptyState text={search?"Aramanızla eşleşen kayıt yok":"Henüz kayıt yok"} onAdd={()=>setModal("new")} S={SS}/>:module==="jobs"?filtered.map(a=><JobCard key={a.id} app={a} onClick={()=>setModal(a)} S={SS}/>):module==="exams"?filtered.map(e=><ExamCard key={e.id} exam={e} onClick={()=>setModal(e)} S={SS}/>):filtered.map(m=><MastersCard key={m.id} item={m} onClick={()=>setModal(m)} S={SS}/>)}
      </>}
      {modal&&module==="jobs"&&<JobModal app={modal==="new"?null:modal} onSave={save(setJobs)} onClose={()=>setModal(null)} onDelete={del(setJobs)} S={SS}/>}
      {modal&&module==="exams"&&<ExamModal exam={modal==="new"?null:modal} onSave={save(setExams)} onClose={()=>setModal(null)} onDelete={del(setExams)} S={SS}/>}
      {modal&&module==="masters"&&<MastersModal item={modal==="new"?null:modal} onSave={save(setMasters)} onClose={()=>setModal(null)} onDelete={del(setMasters)} S={SS}/>}
      {settingsOpen&&<SettingsModal settings={settings} onSave={s=>{setSettings(s);setSettingsOpen(false)}} onClose={()=>setSettingsOpen(false)} S={SS}/>}
    </div>
  </div>
}
